select agent_account as agentAccount,
IFNULL(sum(fee_amount), 0) as feeAmount,
IFNULL(sum(arrive_amount), 0) as amount,
currency_code as currency
from user_deposit_withdrawal
where status = 101

    AND type = #{vo.fundsOperateType}


    AND currency_code = #{vo.currency}


    AND agent_account IN

        #{value}


and updated_time  >=  #{vo.startTime}
and updated_time  <=  #{vo.endTime}
group by agent_account, currency_code

SELECT aa.myDay , aa.currencyCode, IFNULL(sum( aa.depositAmount ), 0) depositAmount, IFNULL(sum( aa.withdrawAmount ), 0) withdrawAmount FROM ( SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(updated_time/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') myDay, currency_code currencyCode, IFNULL(sum( arrive_amount ), 0) depositAmount, IFNULL(sum( apply_amount ), 0) withdrawAmount FROM user_deposit_withdrawal
and site_code = #{siteCode}
AND `type` = #{type}
AND `currency_code` = #{currencyCode}
AND `status` = 101 AND customer_status = 1
AND agent_id = #{agentId}
AND updated_time >= #{start}
AND updated_time <= #{end}
GROUP BY myDay,currency_code
UNION ALL
SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(updated_time/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') myDay, currency_code currencyCode, IFNULL(sum( adjust_amount ), 0) depositAmount, IFNULL(sum( adjust_amount ), 0) withdrawAmount FROM user_manual_up_down_record
AND `adjust_way` = 1 AND `adjust_type` in (4)
AND `adjust_way` = 2 AND `adjust_type` in (4)
AND `currency_code` = #{currencyCode}
AND agent_id = #{agentId}
AND updated_time >= #{start}
AND updated_time <= #{end}
GROUP BY myDay,currency_code
UNION ALL
SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(deposit_time/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') as myDay, currency_code as currencyCode, IFNULL(sum( amount ), 0) depositAmount, 0 withdrawAmount FROM agent_deposit_subordinates
AND agent_id = #{agentId}
AND currency_code = #{currencyCode}
AND deposit_time >= #{start}
AND deposit_time <= #{end}
GROUP BY myDay,currency_code
) aa GROUP BY aa.myDay,aa.currencyCode

SELECT aa.myDay myDay, aa.currencyCode, IFNULL(sum( aa.depositAmount ), 0) depositAmount, IFNULL(sum( aa.withdrawAmount ), 0) withdrawAmount FROM ( SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(updated_time/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') myDay, currency_code as currencyCode, IFNULL(apply_amount, 0) depositAmount, IFNULL(apply_amount, 0) withdrawAmount FROM user_deposit_withdrawal
and site_code = #{siteCode}
AND `type` = #{type}
AND `currency_code` = #{currencyCode}
AND `status` = 101
AND updated_time >= #{start}
AND updated_time <= #{end}
UNION ALL
SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(updated_time/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') myDay, currency_code as currencyCode, IFNULL(CASE WHEN adjust_way = 1 THEN adjust_amount ELSE 0 END, 0) AS depositAmount, IFNULL(CASE WHEN adjust_way = 2 THEN adjust_amount ELSE 0 END, 0) AS withdrawAmount FROM user_manual_up_down_record
AND `adjust_way` = 1 AND `adjust_type` in (4) and balance_change_status = 1
AND `adjust_way` = 2 AND `adjust_type` in (4) and balance_change_status = 1
AND updated_time >= #{start}
AND updated_time <= #{end}
AND `currency_code` = #{currencyCode}
and site_code = #{siteCode}
UNION ALL
SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(deposit_time/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') myDay, currency_code as currencyCode, IFNULL(amount , 0) depositAmount, 0 withdrawAmount FROM agent_deposit_subordinates
AND deposit_time >= #{start}
AND deposit_time <= #{end}
and site_code = #{siteCode}
AND `currency_code` = #{currencyCode}
) aa GROUP BY aa.myDay,aa.currencyCode

SELECT aa.myDay myDay, count(DISTINCT user_id) userCount FROM ( SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(updated_time/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') myDay, user_id FROM user_deposit_withdrawal
and site_code = #{siteCode}
AND `type` = #{type}
AND `status` = 101
AND updated_time >= #{start}
AND updated_time <= #{end}
GROUP BY myDay,user_id
UNION ALL
SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(updated_time/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') myDay, user_id FROM user_manual_up_down_record
AND `adjust_way` = 1 AND `adjust_type` in (4) and balance_change_status = 1
AND `adjust_way` = 2 AND `adjust_type` in (4) and balance_change_status = 1
AND updated_time >= #{start}
AND updated_time <= #{end}
and site_code = #{siteCode}
GROUP BY myDay,user_id
UNION ALL
SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(deposit_time/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') as myDay, user_id FROM agent_deposit_subordinates
AND deposit_time >= #{start}
AND deposit_time <= #{end}
and site_code = #{siteCode}
GROUP BY myDay,user_id
) aa GROUP BY aa.myDay

SELECT
IFNULL(sum( arrive_amount ), 0) arriveAmount,
IFNULL(sum( apply_amount ), 0) applyAmount
FROM
user_deposit_withdrawal


        and site_code = #{siteCode}


        AND agent_account = #{agentAccount}


        AND user_account = #{userAccount}


        AND `type` = #{type}

    AND `status` = 101
    AND customer_status = 1

        AND updated_time  >=  #{startTime}


        AND updated_time  <=  #{endTime}

SELECT aa.currencyCode, IFNULL(sum( aa.depositAmount ), 0) depositAmount, IFNULL(sum( aa.withdrawAmount ), 0) withdrawAmount FROM ( SELECT currency_code as currencyCode, IFNULL(sum(CASE WHEN type = 1 then apply_amount else 0 end ), 0) depositAmount, IFNULL(sum(CASE when type = 2 then apply_amount else 0 end ), 0) withdrawAmount FROM user_deposit_withdrawal
and site_code = #{siteCode}
AND `status` = 101
AND updated_time >= #{start}
AND updated_time <= #{end}
GROUP BY currencyCode
UNION ALL
SELECT currency_code as currencyCode, IFNULL(sum( adjust_amount ), 0) depositAmount, 0 withdrawAmount FROM user_manual_up_down_record
AND `adjust_way` = 1 AND `adjust_type` in (4) and balance_change_status = 1
AND updated_time >= #{start}
AND updated_time <= #{end}
and site_code = #{siteCode}
GROUP BY currencyCode UNION ALL SELECT currency_code as currencyCode, 0 withdrawAmount, IFNULL(sum( adjust_amount ), 0) depositAmount FROM user_manual_up_down_record
AND `adjust_way` = 2 AND `adjust_type` in (4) and balance_change_status = 1
AND updated_time >= #{start}
AND updated_time <= #{end}
and site_code = #{siteCode}
GROUP BY currencyCode UNION ALL SELECT currency_code as currencyCode, IFNULL(sum( amount ), 0) depositAmount, 0 withdrawAmount FROM agent_deposit_subordinates
AND deposit_time >= #{start}
AND deposit_time <= #{end}
and site_code = #{siteCode}
GROUP BY currencyCode
) aa GROUP BY aa.currencyCode

SELECT
user_account as userAccount,
IFNULL(sum( arrive_amount ), 0) as arriveAmount
FROM
user_deposit_withdrawal


        and site_code = #{siteCode}


        AND agent_account = #{agentAccount}

    AND `type` = 1
    AND `status` = 101
    AND customer_status = 1

        AND updated_time  >=  #{startTime}


        AND updated_time  <=  #{endTime}


group by user_account

SELECT
user_account as userAccount,
IFNULL(sum( apply_amount ), 0) as applyAmount
FROM
user_deposit_withdrawal


        and site_code = #{siteCode}


        AND agent_account = #{agentAccount}

    AND `type` = 2
    AND `status` = 101
    AND customer_status = 1

        AND updated_time  >=  #{startTime}


        AND updated_time  <=  #{endTime}


group by user_account

SELECT site_code,
user_id,
user_account,
currency_code,
sum(arrive_amount) arrive_amount
from user_deposit_withdrawal
where `status` = '101'
and type = '1'
and site_code = #{siteCode,jdbcType=VARCHAR}
and deposit_withdraw_type_code = #{rechargeWithdrawCode}
and updated_time >= #{startTime,jdbcType=BIGINT}
