SELECT * FROM (SELECT udw.type AS tradeType, udw.order_no AS orderNo, udw.created_time AS tradeTime, udw.apply_amount AS tradeAmount, udw.arrive_amount AS arriveAmount, udw.customer_status AS tradeStatus, CASE WHEN udw.type = 1 and udw.deposit_withdraw_type_code = 'bank_card' THEN 'bank_card_recharge' WHEN udw.type = 1 and udw.deposit_withdraw_type_code = 'electronic_wallet' THEN 'electronic_wallet_recharge' WHEN udw.type = 1 and udw.deposit_withdraw_type_code = 'crypto_currency' THEN 'crypto_currency_recharge' WHEN udw.type = 2 and udw.deposit_withdraw_type_code = 'bank_card' THEN 'bank_card_withdraw' WHEN udw.type = 2 and udw.deposit_withdraw_type_code = 'electronic_wallet' THEN 'electronic_wallet_withdraw' WHEN udw.type = 2 and udw.deposit_withdraw_type_code = 'crypto_currency' THEN 'crypto_currency_withdraw' WHEN udw.type = 2 and udw.deposit_withdraw_type_code = 'manual_withdraw' THEN 'manual_withdraw' ELSE '' END AS tradeWayType, '0' AS exchangeRate, udw.deposit_withdraw_way AS tradeWay, IF(udw.type = 1,srw.way_icon,sww.way_icon) AS tradeWayIcon FROM user_deposit_withdrawal udw LEFT JOIN system_recharge_way srw ON srw.id = udw.deposit_withdraw_way_id LEFT JOIN system_withdraw_way sww ON sww.id = udw.deposit_withdraw_way_id WHERE udw.user_id = #{vo.userId} AND udw.created_time >= #{vo.startTime} AND udw.created_time <= #{vo.endTime} UNION ALL SELECT umdr.adjust_way AS tradeType, umdr.order_no AS orderNo, umdr.created_time AS tradeTime, umdr.adjust_amount AS tradeAmount, umdr.adjust_amount AS arriveAmount, IF(umdr.balance_change_status = '0','2','1') AS tradeStatus, IF(umdr.adjust_way = '1','manual_up','manual_down') AS tradeWayType, '0' AS exchangeRate, '' AS tradeWay, '' AS tradeWayIcon FROM user_manual_up_down_record umdr WHERE umdr.user_id = #{vo.userId} AND umdr.audit_status = 3 AND umdr.created_time >= #{vo.startTime} AND umdr.created_time <= #{vo.endTime} UNION ALL SELECT '1' AS tradeType, ads.order_no AS orderNo, ads.created_time AS tradeTime, ads.amount AS tradeAmount, ads.amount AS arriveAmount, '1' AS tradeStatus, 'superior_transfer' AS tradeWayType, '0' AS exchangeRate, '' AS tradeWay, '' AS tradeWayIcon FROM agent_deposit_subordinates ads WHERE ads.user_id = #{vo.userId} AND ads.deposit_time >= #{vo.startTime}
) tradeRecord WHERE 1=1
AND tradeRecord.tradeStatus = #{vo.tradeStatus}
AND tradeRecord.tradeType = #{vo.tradeType}
ORDER BY tradeRecord.tradeTime DESC

SELECT * FROM (SELECT '2' AS tradeType, udw.order_no AS orderNo, udw.updated_time AS tradeTime, udw.apply_amount AS tradeAmout, udw.customer_status AS tradeStatus, CASE WHEN udw.type = 1 and udw.deposit_withdraw_type_code = 'bank_card' THEN 'bank_card_recharge' WHEN udw.type = 1 and udw.deposit_withdraw_type_code = 'electronic_wallet' THEN 'electronic_wallet_recharge' WHEN udw.type = 1 and udw.deposit_withdraw_type_code = 'crypto_currency' THEN 'crypto_currency_recharge' WHEN udw.type = 2 and udw.deposit_withdraw_type_code = 'bank_card' THEN 'bank_card_withdraw' WHEN udw.type = 2 and udw.deposit_withdraw_type_code = 'electronic_wallet' THEN 'electronic_wallet_withdraw' WHEN udw.type = 2 and udw.deposit_withdraw_type_code = 'crypto_currency' THEN 'crypto_currency_withdraw' ELSE '' END AS tradeWayType FROM user_deposit_withdrawal udw WHERE udw.user_id = #{vo.userId} AND udw.type = '2' AND udw.updated_time >= #{vo.startTime} AND udw.updated_time <= #{vo.endTime} UNION ALL SELECT '2' AS tradeType, umdr.order_no AS orderNo, umdr.updated_time AS tradeTime, umdr.adjust_amount AS tradeAmout, '1' AS tradeStatus, 'manual_down' AS tradeWayType FROM user_manual_up_down_record umdr WHERE umdr.user_id = #{vo.userId} AND umdr.adjust_type = '4' AND umdr.adjust_way = '2' AND umdr.audit_status = 3 AND umdr.updated_time >= #{vo.startTime} AND umdr.updated_time <= #{vo.endTime} ) tradeRecord WHERE 1=1
